import{_ as t,o,c as i,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"11. Dispute Resolution Procedure","description":"","frontmatter":{"title":"11. Dispute Resolution Procedure","eba":"Medical Specialists 2022-2026","topics":["leave","parental-leave","disputes","flexible-work"]},"headers":[],"relativePath":"ebas/medical-specialists/consultation-disputes/11-dispute-resolution-procedure.md","filePath":"ebas/medical-specialists/consultation-disputes/11-dispute-resolution-procedure.md"}'),r={name:"ebas/medical-specialists/consultation-disputes/11-dispute-resolution-procedure.md"};function n(a,e,p,l,h,c){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="_11-dispute-resolution-procedure" tabindex="-1">11. Dispute Resolution Procedure <a class="header-anchor" href="#_11-dispute-resolution-procedure" aria-label="Permalink to &quot;11. Dispute Resolution Procedure&quot;">​</a></h1><p>The purpose of this clause is to provide for the timely, constructive resolution of disputes, where possible, within the work place or, where necessary, at the Fair Work Commission.</p><p><strong>11.1</strong> Resolution of disputes and grievances</p><p><strong>(a)</strong> For the purpose of this clause 11, a dispute includes a grievance.</p><p><strong>(b)</strong> This dispute resolution procedure will apply to any dispute arising in relation to:</p><p><strong>(i)</strong> this Agreement (for the avoidance of doubt, this includes a request for flexible working arrangements or a request for an additional 12 months’ parental leave);</p><p><strong>(ii)</strong> the NES; or</p><p><strong>(iii)</strong> matters purported to be saved due to the operation of the Savings provision; or</p><p><strong>(iv)</strong> the 2018 Specialists or Doctors in Training Agreement where a dispute was identified in writing to the Health Service prior to this Agreement coming into operation.</p><p><strong>(c)</strong> A Party for the purposes of this clause is the Doctor/s or the Employer that are the subject to the dispute.</p><p><strong>(d)</strong> A Party subject to the dispute may choose to be represented at any stage by a representative including the Association or employer organisation. A representative, including the Association or employer organisation on behalf of a Health Service, may initiate a dispute.</p><p><strong>11.2</strong> Obligations</p><p><strong>(a)</strong> The Parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in this clause and must cooperate to ensure that these processes are carried out expeditiously.</p><p><strong>(b)</strong> While the dispute resolution procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>(c)</strong> This requirement does not apply where a Doctor:</p><p><strong>(i)</strong> has a reasonable concern about an imminent risk to their health or safety;</p><p><strong>(ii)</strong> has advised the Health Service of the concern; and</p><p><strong>(iii)</strong> has not unreasonably failed to comply with a direction by the Health Service to perform other available work that is safe and appropriate for the Doctor to perform.</p><p><strong>(d)</strong> No Party to a dispute or person covered by the Agreement will be prejudiced with respect to the resolution of the dispute by continuing work under subclause 11.2(b).</p><p><strong>11.3</strong> Dispute settlement facilitation</p><p><strong>(a)</strong> Where the chosen representative is another Doctor employed by the Health Service, that Doctor will be released by the Health Service from normal duties (without loss of pay) as is reasonably necessary to enable them to represent the Doctor/s including:</p><p><strong>(i)</strong> investigating the circumstances of the dispute; and</p><p><strong>(ii)</strong> participating in the processes to resolve the dispute, including conciliation and arbitration.</p><p><strong>(b)</strong> A Doctor who is a Party to the dispute will be released by the Health Service from normal duties (without loss of pay) as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Health Service.</p><p><strong>11.4</strong> Discussion of dispute at workplace</p><p><strong>(a)</strong> The Parties will attempt to resolve the dispute at the workplace as follows:</p><p><strong>(i)</strong> in the first instance by discussions between the Doctor/s and the Doctor’s line manager or other relevant supervisor; and</p><p><strong>(ii)</strong> if the dispute is still unresolved, by discussions between the Doctor/s and more senior managers.</p><p>Nothing in this subclause 11.4 prevents the Parties from conducting their discussions in writing, subject to subclause 11.4.</p><p><strong>(b)</strong> The discussions at subclause 11.4(a) will take place within fourteen days or such longer period as mutually agreed, save that agreement will not be unreasonably withheld.</p><p><strong>(c)</strong> Where a Party believes the requirements of this subclause 11.4 have not been complied with, they will notify the other of their concern in writing as soon as practicable.</p><p><strong>(d)</strong> If a dispute cannot be resolved at the workplace it may be referred by a party to the dispute or representative to the FWC for conciliation and, if the matter in dispute remains unresolved, arbitration.</p><p><strong>11.5</strong> Disputes of a collective character</p><p>Disputes of a collective character may be dealt with more expeditiously by an early reference to the FWC. However, no dispute of a collective character may be referred to the FWC directly without a genuine attempt to resolve the dispute at the workplace level.</p><p><strong>11.6</strong> Conciliation</p><p><strong>(a)</strong> Where a dispute is referred for conciliation, the FWC member will do everything the member deems right and proper to assist the parties to settle the dispute.</p><p><strong>(b)</strong> Conciliation before the FWC is complete when:</p><p><strong>(i)</strong> the Parties to the dispute agree that it is settled; or</p><p><strong>(ii)</strong> the FWC member conducting the conciliation, either on their own motion or after an application by a Party, is satisfied there is no likelihood that further conciliation will result in settlement within a reasonable period; or</p><p><strong>(iii)</strong> the Parties to the dispute inform the FWC member there is no likelihood the dispute will be settled and the member does not have substantial reason to refuse to regard conciliation as complete.</p><p><strong>11.7</strong> Arbitration</p><p><strong>(a)</strong> If, when conciliation is complete, the dispute is not settled, either party may request the FWC proceed to determine the dispute by arbitration.</p><p><strong>(b)</strong> The FWC member that conciliated the dispute will not arbitrate the dispute if a Party objects to the member doing so.</p><p><strong>(c)</strong> If the dispute resolution procedure results in a finding by the FWC that a breach of the Savings provision of this Agreement has occurred, the parties agree that the order of the FWC under this subclause 11.7 will be to restore all rights and entitlements affected by the breach to the state which would have prevailed if the breach had not occurred.</p><p><strong>(d)</strong> Subject to subclause 11.7(e) below, a decision of the FWC is binding upon the persons covered by this Agreement.</p><p><strong>(e)</strong> An appeal lies to a Full Bench of the FWC, with the leave of the Full Bench, against a determination of a single member of the FWC made pursuant to this clause.</p><p><strong>11.8</strong> Conduct of matters before the FWC</p><p><strong>(a)</strong> Subject to any agreement between the Parties to the dispute in relation to a particular dispute or grievance and the provisions of this clause, in dealing with a dispute or grievance through conciliation or arbitration, the FWC will conduct the matter in accordance with sections 577, 578 and Subdivision B of Division 3 of Part 5-1 of the Act.</p><p><strong>(b)</strong> For the avoidance of doubt, nothing in this clause 11 affects the operation of</p><p>Plain language terms: dispute, grievance, FWC dispute.</p>',50)])])}const g=t(r,[["render",n]]);export{d as __pageData,g as default};
